#graphql
  mutation StoreCreditConformanceCustomerCreate($input: CustomerInput!) {
    customerCreate(input: $input) {
      customer {

  id
  email
  displayName
  storeCreditAccounts(first: 5) {
    nodes {
      id
      balance {
        amount
        currencyCode
      }
    }
    pageInfo {
      hasNextPage
      hasPreviousPage
    }
  }
  queriedStoreCreditAccounts: storeCreditAccounts(first: 5, query: "currency_code:CHF") {
    nodes {
      id
      balance {
        amount
        currencyCode
      }
    }
    pageInfo {
      hasNextPage
      hasPreviousPage
      startCursor
      endCursor
    }
  }

      }
      userErrors {
        field
        message
      }
    }
  }

#graphql
  mutation StoreCreditAccountCreditParity($id: ID!, $creditInput: StoreCreditAccountCreditInput!) {
    storeCreditAccountCredit(id: $id, creditInput: $creditInput) {
      storeCreditAccountTransaction {

  amount {
    amount
    currencyCode
  }
  balanceAfterTransaction {
    amount
    currencyCode
  }
  event
  origin
  account {
    id
    balance {
      amount
      currencyCode
    }
    owner {
      ... on Customer {
        id
        email
      }
    }
  }

      }
      userErrors {
        field
        message
        code
      }
    }
  }

